code = """import json

# Get the price data summary
price_info = locals()['var_functions.query_db:28']

# Filter indices that have data from 2000 or earlier
indices_2000 = []
for record in price_info:
    first_date = record['first_date']
    # Parse year from the date string
    year_str = first_date.split(',')[1].strip()
    year = int(year_str)
    if year <= 2000:
        indices_2000.append(record['Index'])

print('Indices with data from 2000 or earlier:', sorted(indices_2000))
print('Count:', len(indices_2000))

# Map indices to countries/exchanges based on the hint
index_to_country = {
    'N225': {'country': 'Japan', 'exchange': 'Tokyo Stock Exchange'},
    'HSI': {'country': 'Hong Kong', 'exchange': 'Hong Kong Stock Exchange'},
    'GDAXI': {'country': 'Germany', 'exchange': 'Frankfurt Stock Exchange'},
    'GSPTSE': {'country': 'Canada', 'exchange': 'Toronto Stock Exchange'},
    'IXIC': {'country': 'United States', 'exchange': 'NASDAQ'},
    'NYA': {'country': 'United States', 'exchange': 'New York Stock Exchange'},
    'SSMI': {'country': 'Switzerland', 'exchange': 'SIX Swiss Exchange'}
}

print('\nIndex mapping:')
for idx in sorted(indices_2000):
    if idx in index_to_country:
        print(f"  {idx}: {index_to_country[idx]['country']} ({index_to_country[idx]['exchange']})")
    else:
        print(f"  {idx}: Country unknown")

# Return the filtered indices
result = {
    'valid_indices': sorted(indices_2000),
    'mapping': index_to_country
}

print('\n---BEGIN PRINT FORMAT---')
print('__RESULT__:')
print(json.dumps(result))
print('---END PRINT FORMAT---')"""

